import{_ as e,c as o,o as t,a3 as a}from"./chunks/framework.6s30bTua.js";const f=JSON.parse('{"title":"Uniform Resource Locator (URL)","description":"A Uniform Resource Locator (URL), colloquially termed a web address","frontmatter":{"title":"Uniform Resource Locator (URL)","description":"A Uniform Resource Locator (URL), colloquially termed a web address"},"headers":[],"relativePath":"Concepts/Web/URL.md","filePath":"Concepts/Web/URL.md","lastUpdated":1668244097000}'),i={name:"Concepts/Web/URL.md"},l=a('<h1 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h1><p>A Uniform Resource Locator (URL), colloquially termed a web address, is a reference to a web resource that specifies its location on a computer network and a mechanism for retrieving it.</p><ul><li>Defined in <a href="https://datatracker.ietf.org/doc/html/rfc1738" target="_blank" rel="noreferrer">RFC 1738</a> in 1994 by Tim Berners-Lee</li></ul><p>A URL is a specific type of Uniform Resource Identifier (URI),</p><ul><li><strong>URL</strong> is subset of <strong>URI</strong></li></ul><p>URL are mostly used to reference:</p><ul><li>Web pages (<a href="./HTTP.html">http</a>)</li><li>File transfer (<code>ftp</code>)</li><li>email (<code>mailto</code>)</li><li>Database access (<code>JDBC</code>)</li><li>And many other applications</li></ul><h2 id="url-syntax" tabindex="-1">URL Syntax <a class="header-anchor" href="#url-syntax" aria-label="Permalink to &quot;URL Syntax&quot;">​</a></h2><p>Every HTTP URL conforms to the syntax of a generic URI (consist of a hierarchical sequence of 5 components):</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes ayu-dark ayu-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#BFBDB6;--shiki-dark:#BFBDB6;">URI = scheme &quot;:&quot; [&quot;//&quot; authority] path [&quot;?&quot; query] [&quot;#&quot; fragment]</span></span></code></pre></div><p>Where the <code>authority</code> component divides into 3 subcomponents:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes ayu-dark ayu-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#BFBDB6;--shiki-dark:#BFBDB6;">authority = [userinfo &quot;@&quot;] host [&quot;:&quot; port]</span></span></code></pre></div><p>The URI comprises:</p><ul><li><p><strong>Scheme</strong>: A non-empty scheme component followed by a colon (<code>:</code>):</p><ul><li>Begins with a letter</li><li>Followed by any combination of letters, digits, plus (<code>+</code>), period (<code>.</code>), or hyphen (<code>-</code>)</li><li>Canonical form Lowercase (they are case-insensitive)</li><li>E.g. <code>http</code>, <code>https</code>, <code>ftp</code>, <code>mailto</code>, <code>file</code>, <code>data</code>, and <code>irc</code></li></ul></li><li><p><strong>Authority</strong>: An optional component preceded by 2 slashes (<code>//</code>):</p><ul><li><p><code>userinfo</code> (optional) subcomponent that may consist of a user name and an optional password proceeded by a colon (<code>:</code>), followed by an at symbol (<code>@</code>)</p><ul><li><code>username:password</code>: is depreciated for security reasons (it uses plain text)</li></ul></li><li><p><code>host</code>: A subcomponent consisting of either a registered name or an IP address</p><ul><li>IPv4 addresses must be in dot-decimal notation</li><li>IPv6 addresses must be enclosed in brackets (<code>[]</code>)</li></ul></li><li><p><code>port</code>: optional subcomponent preceded by a colon (<code>:</code>)</p></li></ul></li><li><p><strong>Path</strong>: A component, consisting of a sequence of path segments separated by a slash (<code>/</code>)</p><ul><li>Always defined and may be empty (0 length)</li><li>In <code>http</code> and <code>https</code> URIs, the last part of a path is named <code>pathinfo</code> (optional)</li><li>For more information <a href="https://en.wikipedia.org/wiki/URL" target="_blank" rel="noreferrer">Wiki URL</a></li></ul></li><li><p><strong>Query</strong>: An optional component preceded by a question mark (<code>?</code>), containing a query string of non-hierarchical data:</p><ul><li>Its syntax is not well defined</li><li>By convention is most often a sequence of attribute–value pairs separated by a delimiter.</li></ul></li><li><p><strong>Fragment</strong>: An optional component proceeded by a hash (<code>#</code>):</p><ul><li>The fragment contains a fragment identifier providing direction to a secondary resource, such as a section heading in an article identified by the remainder of the URI.</li><li>When the primary resource is an HTML document, the fragment is often an id attribute of a specific element, and web browsers will scroll this element into view.</li></ul></li></ul><p>Example URL <code>http://www.example.com:81/a/b.html?user=Alice&amp;year=2049#heading</code> is divided into different parts:</p><ul><li><p>Scheme: <code>http</code> (Protocol)</p></li><li><p>Authority: Domain Name + Port</p><ul><li>Domain Name: <code>www.example.com</code> (Hostname)</li><li>Port Number: <code>81</code></li></ul></li><li><p>Path: <code>/a/b.html</code> (Path to the file or API endpoints or dynamically generated)</p></li><li><p>Query: <code>?user=Alice&amp;year=2049</code> (Parameters)</p></li><li><p>Fragment: <code>#heading</code> (Anchor)</p></li></ul><p>Ways to specify a URL:</p><ul><li>Full URL: <code>&lt;a href=&#39;http://stanford.edu/news/2019/&#39;&gt;2019 News&lt;/a&gt;</code></li><li>Relative URL: <code>&lt;a href=&#39;september&#39;&gt;September News&lt;/a&gt;</code><ul><li>Same as: <code>http://stanford.edu/news/2019/september</code></li></ul></li><li>Absolute URL: <code>&lt;a href=&#39;/events&#39;&gt;Events&lt;/a&gt;</code><ul><li>It removes everything till the root and adds <code>/event</code> to it unlike relative URL</li><li>Same as: <code>http://stanford.edu/events</code></li></ul></li><li>Fragment URL: <code>&lt;a href=&#39;#section3&#39;&gt;Jump to Section 3&lt;/a&gt;</code><ul><li>Scrolls to <code>&lt;a href=&#39;section3&#39; /&gt;</code> within page</li><li>Same as: <code>http://stanford.edu/events#section3</code></li></ul></li></ul><p>Some HTML tags that can include URL:</p><ul><li><code>&lt;img&gt;</code></li><li><code>&lt;video&gt;</code>, <code>&lt;audio&gt;</code></li><li><code>&lt;canvas&gt;</code></li><li><code>&lt;link&gt;</code>, <code>&lt;style&gt;</code></li><li><code>&lt;script&gt;</code></li></ul><div class="tip custom-block"><p class="custom-block-title">TRAILING FORWARD SLASH</p><p>If you add trailing <code>/</code> to the URL?</p></div><h2 id="internationalized-url" tabindex="-1">Internationalized URL <a class="header-anchor" href="#internationalized-url" aria-label="Permalink to &quot;Internationalized URL&quot;">​</a></h2><p>An Internationalized Resource Identifier (IRI) is a form of URL that includes Unicode characters. All modern browsers support IRIs.</p><ul><li><p>The domain name in the IRI is known as an Internationalized Domain Name (IDN).</p></li><li><p>Web and Internet software automatically convert the domain name into <code>punycode</code> usable by the Domain Name System; for example, the Chinese URL <code>http://例子.卷筒纸</code> becomes <code>http://xn--fsqu00a.xn--3lr804guic/</code>. The <code>xn--</code> indicates that the character was not originally ASCII</p><ul><li>Punycode is a representation of Unicode with the limited ASCII character subset used for Internet hostnames</li></ul></li><li><p>The URL path name can also be specified by the user in the local writing system. If not already encoded, it is converted to UTF-8, and any characters not part of the basic URL character set are escaped as hexadecimal using percent-encoding; for example, the Japanese URL <code>http://example.com/引き割り.html</code> becomes <code>http://example.com/%E5%BC%95%E3%81%8D%E5%89%B2%E3%82%8A.html</code>. The target computer decodes the address and displays the page.</p></li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://www.punycoder.com/" target="_blank" rel="noreferrer">Punycode converter</a></li></ul>',26),n=[l];function c(s,r,d,p,u,h){return t(),o("div",null,n)}const g=e(i,[["render",c]]);export{f as __pageData,g as default};
